const r = $input.first().json || {};
const f = v => (v === null || v === undefined) ? '-' : String(v);
const dt = v => v ? new Date(v).toLocaleString('id-ID', { timeZone: 'Asia/Jakarta', dateStyle: 'medium', timeStyle: 'short' }) : '-';
const resultMessage =
  '📊 WAG Chat — Overview\n\n' +
  'Groups: ' + f(r.groups_total) + ' total, ' + f(r.groups_active) + ' active\n' +
  'Messages: ' + f(r.messages_total) + ' total\n' +
  '  • today: ' + f(r.messages_today) + '\n' +
  '  • yesterday: ' + f(r.messages_yesterday) + '\n' +
  '  • last message: ' + dt(r.last_message_at) + '\n\n' +
  'Summaries: ' + f(r.summaries_total) + ' total, ' + f(r.summaries_yesterday) + ' for yesterday';
return [{ json: { resultMessage } }];

const rows = $input.all().map(i => i.json).filter(r => r && r.chat_jid);
const dt = v => v ? new Date(v).toLocaleString('id-ID', { timeZone: 'Asia/Jakarta', dateStyle: 'short', timeStyle: 'short' }) : 'no messages yet';
const resultMessage = rows.length
  ? ('👥 Registered groups (' + rows.length + '):\n\n' + rows.map(r =>
      (r.active ? '🟢' : '⚪') + ' ' + r.project_name + '\n' +
      '    ' + r.chat_jid + '  →  ' + r.send_to + '\n' +
      '    ' + (r.msg_count || 0) + ' msgs · last: ' + dt(r.last_msg)).join('\n\n'))
  : 'No groups registered yet. Use Quick Setup or the Admin workflow.';
return [{ json: { resultMessage } }];

const rows = $input.all().map(i => i.json).filter(r => r && r.chat_jid);
const t = v => v ? new Date(v).toLocaleString('id-ID', { timeZone: 'Asia/Jakarta', dateStyle: 'short', timeStyle: 'short' }) : '';
const body = rows.map(r => {
  const txt = (r.message && String(r.message).trim()) ? r.message : (r.media_type ? '[' + r.media_type + ']' : '(empty)');
  return '[' + t(r.timestamp) + '] ' + (r.sender_name || 'Unknown') + ': ' + txt;
});
const resultMessage = rows.length
  ? ('💬 Recent messages (' + rows.length + ', newest first):\n\n' + body.join('\n'))
  : 'No messages match. Clear the Chat JID filter to see all, or wait for ingest.';
return [{ json: { resultMessage } }];

const rows = $input.all().map(i => i.json).filter(r => r && r.chat_jid);
const resultMessage = rows.length
  ? ('🗒️ Daily summaries (' + rows.length + ', newest first):\n\n' + rows.map(r => {
      const head = String(r.summary_text || '').split('\n')[0];
      const d = String(r.summary_date).slice(0, 10);
      return d + '  [' + r.status + ']  ' + r.chat_jid + '\n' +
             '    ' + (r.message_count || 0) + ' msgs · ' + (r.member_count || 0) + ' members' +
             (head ? '\n    ' + head : '');
    }).join('\n\n'))
  : 'No summaries logged yet. They appear after the daily run.';
return [{ json: { resultMessage } }];

const rows = $input.all().map(i => i.json).filter(r => r && r.key);
const resultMessage = rows.length
  ? ('⚙️ Config (wag_config):\n\n' + rows.map(r => r.key + ' = ' + (r.value ? r.value : '(blank)')).join('\n'))
  : 'No config rows yet. Quick Setup writes gowa_base_url / gowa_device_id / alert_to.';
return [{ json: { resultMessage } }];

